import type { AudioEffect } from "./BaseEffect.js";

export interface ReverbParams {
  decay: number;
  mix: number;
}

const COMB_DELAYS = [29, 37, 44, 51];
const ALLPASS_DELAYS = [5, 9];
const COMB_GAIN = 0.8;

export class ReverbEffect implements AudioEffect {
  readonly name = "reverb";

  private combBuffers: Float64Array[][] = [];
  private combPositions: number[][] = [];
  private allpassBuffers: Float64Array[][] = [];
  private allpassPositions: number[][] = [];
  private _decay: number;
  private _mix: number;
  private _sampleRate: number;

  constructor(sampleRate: number, channels: number, params?: Partial<ReverbParams>) {
    this._sampleRate = sampleRate;
    this._decay = params?.decay ?? 0.5;
    this._mix = params?.mix ?? 0.3;
    this.initBuffers(channels);
  }

  private initBuffers(channels: number): void {
    this.combBuffers = Array.from({ length: channels }, () =>
      COMB_DELAYS.map((d) => new Float64Array(Math.max(1, Math.round((d / 1000) * this._sampleRate)))),
    );
    this.combPositions = Array.from({ length: channels }, () => COMB_DELAYS.map(() => 0));
    this.allpassBuffers = Array.from({ length: channels }, () =>
      ALLPASS_DELAYS.map((d) => new Float64Array(Math.max(1, Math.round((d / 1000) * this._sampleRate)))),
    );
    this.allpassPositions = Array.from({ length: channels }, () => ALLPASS_DELAYS.map(() => 0));
  }

  get decay(): number { return this._decay; }
  get mix(): number { return this._mix; }

  setDecay(v: number): void {
    this._decay = Math.max(0, Math.min(1, v));
  }

  setMix(v: number): void {
    this._mix = Math.max(0, Math.min(1, v));
  }

  isActive(): boolean {
    return this._mix > 0;
  }

  process(samples: Float64Array, channels: number, _frames: number): void {
    const mix = this._mix;
    const decay = this._decay;
    if (mix <= 0) return;

    const limit = Math.min(channels, this.combBuffers.length);

    for (let ch = 0; ch < limit; ch++) {
      const combBufs = this.combBuffers[ch]!;
      const combPos = this.combPositions[ch]!;
      const apBufs = this.allpassBuffers[ch]!;
      const apPos = this.allpassPositions[ch]!;

      for (let i = ch; i < samples.length; i += channels) {
        const input = samples[i]!;

        // Comb filters in parallel
        let wet = 0;
        for (let c = 0; c < combBufs.length; c++) {
          const buf = combBufs[c]!;
          const pos = combPos[c]!;
          const read = buf[pos]!;
          const feedback = COMB_GAIN * decay;
          buf[pos] = input + read * feedback;
          wet += read;
          combPos[c] = (pos + 1) % buf.length;
        }
        wet /= combBufs.length;

        // All-pass filters in series
        for (let a = 0; a < apBufs.length; a++) {
          const buf = apBufs[a]!;
          const pos = apPos[a]!;
          const read = buf[pos]!;
          buf[pos] = wet + read * -0.5;
          wet = read - wet * 0.5;
          apPos[a] = (pos + 1) % buf.length;
        }

        samples[i] = input * (1 - mix) + wet * mix;
      }
    }
  }

  reset(): void {
    for (const ch of this.combBuffers) {
      for (const buf of ch) buf.fill(0);
    }
    for (const ch of this.combPositions) {
      ch.fill(0);
    }
    for (const ch of this.allpassBuffers) {
      for (const buf of ch) buf.fill(0);
    }
    for (const ch of this.allpassPositions) {
      ch.fill(0);
    }
  }
}
